import React, { useEffect, useState } from 'react';
import axios from 'axios';

const RegistroEmpresa = ({ ancho = '100%', alto = '90vh' }) => {
  const [form, setForm] = useState({
    denominacion_social: '',
    nombre_comercial: '',
    nit: '',
    url: '',
    eslogan: '',
    descripcion: '',
    fecha_fundacion: '',
    fecha_cierre: '',
    rubros: [],
    propietarios: [],
    tamanios: [],
    tipos_societarios: [],
    premios: [],
    actividades: []
  });

  const handleInput = (field, value) => {
    setForm((prev) => ({ ...prev, [field]: value }));
  };

  const handleSubmit = async () => {
    try {
      const res = await axios.post('http://localhost:3000/empresas', form);
      alert('✅ Empresa registrada correctamente');
    } catch (err) {
      console.error('Error al registrar empresa:', err);
      alert('❌ Ocurrió un error al registrar la empresa');
    }
  };

  return (
    <div
      className="bg-white border border-gray-300 shadow rounded p-6 overflow-y-auto"
      style={{ width: ancho, height: alto }}
    >
      <h2 className="text-xl font-semibold mb-4">Registro de Empresa</h2>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <input
          type="text"
          placeholder="Denominación Social"
          value={form.denominacion_social}
          onChange={(e) => handleInput('denominacion_social', e.target.value)}
          className="border rounded p-2 w-full"
        />
        <input
          type="text"
          placeholder="Nombre Comercial"
          value={form.nombre_comercial}
          onChange={(e) => handleInput('nombre_comercial', e.target.value)}
          className="border rounded p-2 w-full"
        />
        <input
          type="text"
          placeholder="NIT"
          value={form.nit}
          onChange={(e) => handleInput('nit', e.target.value)}
          className="border rounded p-2 w-full"
        />
        <input
          type="text"
          placeholder="URL de imagen en Cloudinary"
          value={form.url}
          onChange={(e) => handleInput('url', e.target.value)}
          className="border rounded p-2 w-full"
        />
        <input
          type="text"
          placeholder="Eslogan"
          value={form.eslogan}
          onChange={(e) => handleInput('eslogan', e.target.value)}
          className="border rounded p-2 w-full"
        />
        <input
          type="date"
          placeholder="Fecha Fundación"
          value={form.fecha_fundacion}
          onChange={(e) => handleInput('fecha_fundacion', e.target.value)}
          className="border rounded p-2 w-full"
        />
        <input
          type="date"
          placeholder="Fecha Cierre"
          value={form.fecha_cierre}
          onChange={(e) => handleInput('fecha_cierre', e.target.value)}
          className="border rounded p-2 w-full"
        />
      </div>

      <textarea
        placeholder="Descripción"
        value={form.descripcion}
        onChange={(e) => handleInput('descripcion', e.target.value)}
        className="border rounded p-2 mt-4 w-full"
        rows={4}
      ></textarea>

      <div className="flex justify-end mt-6">
        <button
          onClick={handleSubmit}
          className="bg-black text-white px-4 py-2 rounded hover:bg-gray-800"
        >
          Registrar Empresa
        </button>
      </div>
    </div>
  );
};

export default RegistroEmpresa;
